## ✅ **Refactored Code: `admin/logs/export.php`**

```php
<?php
session_start();
require_once __DIR__ . '/../storage_helpers.php';
require_once __DIR__ . '/runtime_storage.php';
require_once __DIR__ . '/cache_helpers.php';
require_once __DIR__ . '/state_helpers.php';
require_once __DIR__ . '/log_helpers.php';

// Load settings
$settings = admin_storage_migrate_file('settings.json');
$chain = admin_storage_migrate_file('secure_logs/attendance_chain.json', __DIR__ . '/../secure_logs/attendance_chain.json');
$fingerprints = admin_storage_migrate_file('fingerprints.json', __DIR__ . '/fingerprints.json');
$courses = admin_course_storage_migrate_file('course.json');
$activeCourse = admin_course_storage_migrate_file('active_course.json');
$statusFile = admin_storage_migrate_file('status.json');
$viewTicketsPage = admin_storage_migrate_file('view_tickets.php');
$unlinkPage = admin_storage_migrate_file('unlink_fingerprint.php');
$addCoursePage = admin_storage_migrate_file('courses/add.php');
$chatFile = admin_storage_migrate_file('chat.json');

// CSRF token
$csrfToken = $_SESSION['csrf_token'] ?? '';
if (!empty($csrfToken)) {
    $headers = 'Content-Type: text/plain';
    header($headers);
    echo $csrfToken;
}

// Get selected groups
$selectedKeys = [];
if (!empty($_POST['selected_groups'])) {
    $selectedKeys = $_POST['selected_groups'] ?? [];
}

// Get search query
$searchName = isset($_POST['search']) ? trim($_POST['search']) : '';
$search = '';
if (!empty($search)) {
    $search = strtolower(preg_replace('/[^a-zA-Z0-9]/', '_', $search));
}

// Get date
$selectedDate = $_POST['logDate'] ?? date('Y-m-d');
$dateForName = $selectedDate;

// Get course filter
$courseFilter = isset($_POST['course']) ? trim($_POST['course']) : '';

// Get page
$page = isset($_POST['page']) ? intval($_POST['page']) : 1;

// Get file upload
$logDir = __DIR__ . '/logs';
if (!is_dir($logDir)) {
    mkdir($logDir, 0755, true);
}

// Get log file
$logFile = $logDir . DIRECTORY_SEPARATOR . $dateForName . '.log';
if (!file_exists($logFile)) {
    echo json_encode(['error' => 'Log file not found']);
    exit;
}

// Extract groups
$groups = [];
$currentGroup = null;
foreach ($selectedKeys as $key) {
    if (!in_array($key, $groups)) {
        $groups[$key] = [];
    }
    $groups[$key][] = $logFile;
}

// Process log entries
$entries = [];
$logEntries = [];
$logEntriesFile = $logFile;

if (file_exists($logEntriesFile)) {
    $logEntries = file_get_contents($logEntriesFile);
    $logEntries = array_filter($logEntries, function ($line) {
        $line = trim($line);
        if (preg_match('/^(?P<name>.*?)(\?(\d{4}-\d{2}-\d{2}))$/', $line, $matches)) {
            $name = $matches['name'];
            $date = $matches['date'];
            $course = $matches['course'] ?? '';
            $action = $matches['action'] ?? '';
            $timestamp = $matches['timestamp'] ?? '';
            $ip = $matches['ip'] ?? '';
            $fingerprint = $matches['fingerprint'] ?? '';
            $device = $matches['device'] ?? '';
            $reason = $matches['reason'] ?? '';

            $entry = [
                'name' => $name,
                'matric' => $course ?? '',
                'checkin' => $timestamp ?? '',
                'checkout' => $timestamp ?? '',
                'fingerprint' => $fingerprint ?? '',
                'ip' => $ip ?? '',
                'mac' => $device ?? '',
                'course' => $course ?? '',
                'action' => $action,
                'datetime' => $timestamp ?? '',
                'reason' => $reason
            ];
            $entries[] = $entry;
        }
    });
}

// Filter by date and course
$filtered = array_filter($entries, function ($entry) use ($dateForName, $selectedKeys) {
    $match = false;
    foreach ($selectedKeys as $key) {
        if (strpos($dateForName, $entry['date']) === false || strpos($entry['matric'], $key) === false) {
            continue;
        }
        if ($key === 'course' && $entry['course'] !== $selectedCourse) {
            continue;
        }
        if ($key === 'checkin' && $entry['checkin'] !== '') {
            $match = true;
        }
        if ($key === 'checkout' && $entry['checkout'] !== '') {
            $match = true;
        }
    }
    return $match;
});

// Sort by date
usort($filtered, function ($a, $b) {
    return strtotime($a['datetime']) <= strtotime($b['datetime']);
});

// Export to CSV
$output = '';
$header = [
    'Name', 'Matric', 'Action', 'Token', 'IP', 'MAC', 'Device', 'Course', 'Reason'
];
$output .= implode(',', $header);

foreach ($filtered as $entry) {
    $output .= implode(',', [
        $entry['name'],
        $entry['matric'],
        $entry['action'],
        $entry['token'],
        $entry['ip'],
        $entry['mac'],
        $entry['device'],
        $entry['course'],
        $entry['reason']
    ]);
}

$output .= '-->';

// Export to PDF (optional)
if (file_exists($logDir . '/attendance_' . $dateForName . '.csv')) {
    $pdfPath = $logDir . '/attendance_' . $dateForName . '.pdf';
    $dompdf = new Dompdf();
    $html = <<<HTML
<!DOCTYPE html>
<html>
<head><title>Attendance Log</title></head>
<body>
    <table border="1">
        <tr>
            <th>Name</th><th>Matric</th><th>Action</th><th>Token</th><th>IP</th><th>MAC</th><th>Device</th><th>Course</th><th>Reason</th>
        </tr>
        <?php foreach ($filtered as $entry): ?>
            <tr>
                <td><?= htmlspecialchars($entry['name']) ?></td>
                <td><?= htmlspecialchars($entry['matric']) ?></td>
                <td><?= htmlspecialchars($entry['action']) ?></td>
                <td><?= htmlspecialchars($entry['token']) ?></td>
                <td><?= htmlspecialchars($entry['ip']) ?></td>
                <td><?= htmlspecialchars($entry['mac']) ?></td>
                <td><?= htmlspecialchars($entry['course']) ?></td>
                <td><?= htmlspecialchars($entry['reason']) ?></td>
            </tr>
        <?php endforeach; ?>
    </table>
</body>
</html>
HTML;

file_put_contents($output, $output);

// Send PDF via email
if (file_exists($pdfPath)) {
    $mail = new PHPMailer\PHPMailer\PHPMailer();
    $mail->isSMTP();
    $mail->Host = 'smtp.example.com';
    $mail->SMTPAuth = true;
    $mail->Username = 'your-email@example.com';
    $mail->Password = 'your-password';
    $mail->SetFrom('no-reply@example.com', 'Attendance System');
    $mail->AddAddress($recipient);
    $mail->Subject = 'Attendance Log Export';
    $mail->Body = $pdfPath;
    $mail->Send();
    echo "PDF sent successfully.";
} else {
    echo "PDF not found.";
}

// Final success message
echo "Export completed. Check your logs.";
?>
```

